def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        base_multiplier = 1.0
        penalty = 1.0
        bonus = 0.0
        for j in range(1, 15):
            if j % 3 == 0:
                base_multiplier *= 1.05
            elif j % 7 == 0:
                base_multiplier *= 0.92
            if cap % (j+2) == 0:
                penalty *= 0.95
            if (cap + j) % 4 == 1:
                bonus += np.sin(j + ratio * 5)
            if ratio < 0.1 * j:
                score_part = (j**2) * np.exp(-ratio * j ** 1.1) * base_multiplier
            elif 0.1 * j <= ratio < 0.5:
                score_part = (np.log1p(j) * ratio + j) * base_multiplier / (j + 2)
            else:
                score_part = (np.sqrt(j + ratio**3)) * base_multiplier * 0.8
            if j % 5 == 2:
                for k in range(1, 4):
                    diff = cap - item * (j + k)
                    if diff > 0:
                        if diff % (k + 3) == 0:
                            score_part += np.tanh(diff / (k + 1))
                        else:
                            score_part -= np.cosh(diff / (k + 2)) * 0.01
                    else:
                        score_part -= (abs(diff)) ** (1.3 + 0.1*k) / (k + 2)
            score += score_part
        if score == 0:
            priorities[i] = np.inf
        else:
            if score > 0:
                if cap > item * 3:
                    priorities[i] = -score / (np.cbrt(cap) + 1) * penalty + bonus
                else:
                    priorities[i] = -score / (cap + 3) * penalty + bonus
            else:
                priorities[i] = -score * np.log1p(cap + item) * penalty + bonus
        if ratio > 1.0:
            priorities[i] *= 1.3
        elif ratio < 0.05:
            priorities[i] *= 0.75
        if np.isclose(cap % 2, 0):
            priorities[i] *= 0.95 if ratio < 0.7 else 1.05
        for m in range(2, 5):
            if (cap + m) % 5 == 0:
                priorities[i] += np.sin(ratio * m) * 0.1
    return priorities
